noncompliant:
int a = 5;
int b = 5;
bool result = Object.ReferenceEquals(a, b); // Noncompliant: always false for value types

compliant:
int a = 5;
int b = 5;
bool result = a == b; // Correct: use equality operator for value types

// For reference types, ReferenceEquals is appropriate:
string str1 = "hello";
string str2 = "hello";
bool refEqual = Object.ReferenceEquals(str1, str2);
